function stageTone(stage) {
  if (["filed", "m341_concluded", "discharge", "closed"].includes(stage)) return "ok";
  if (["fixes", "approved"].includes(stage)) return "flag";
  if (["submitted", "paralegal", "attorney", "schedule", "sign_done", "m341_docs", "m341_submitted", "finmgmt"].includes(stage)) return "ink";
  return "pending";
}
function needsAction(role, stage) {
  if (role === "paralegal") return ["submitted", "paralegal", "m341_docs", "finmgmt"].includes(stage);
  if (role === "attorney") return ["attorney", "schedule"].includes(stage);
  return false;
}
const initials = (name) => name === "Unassigned" || name === "—" ? "–" : name.split(" ").map((w) => w[0]).slice(0, 2).join("");

